judgeConfig.referenceSolution:
.skip-link {
  position: absolute;
  top: -100px;
  left: 0;
  background: #4f46e5;
  color: white;
  padding: 8px 16px;
  z-index: 100;
  transition: top 0.2s;
}
.skip-link:focus {
  top: 10px;
  left: 10px;
}
